#[derive(thiserror::Error, Debug)]
pub enum RlnScError {
    #[error("RPC transport error: {0}")]
    RpcTransportError(#[from] RpcError<TransportErrorKind>),
    #[error(transparent)]
    Alloy(#[from] alloy::contract::Error),
    #[error("Pending transaction error: {0}")]
    PendingTransactionError(#[from] alloy::providers::PendingTransactionError),
    #[error("Private key cannot be empty")]
    EmptyPrivateKey,
    #[error("Unable to connect with signer: {0}")]
    SignerConnectionError(String),
}

#[async_trait]
pub trait RLNRegister {
    type Error;

    async fn register_user(
        &self,
        address: &Address,
        identity_commitment: U256,
    ) -> Result<(), Self::Error>;
}

sol! {

    // Contract from: status-network-monorepo/status-network-contracts/src/rln/RLN.sol
    // Bytecode compile (in status-network-monorepo):
    // Note: you need to install openzeppelin libs
    //       use: make status-network-contracts-setup for that or follow the instructions manually
    // cd status-network-contracts
    // docker run -v ./:/sources ethereum/solc:0.8.26 --bin --via-ir --optimize --optimize-runs 1 --overwrite  @openzeppelin/contracts=/sources/lib/openzeppelin-contracts/contracts @openzeppelin/contracts-upgradeable=/sources/lib/openzeppelin-contracts-upgradeable/contracts /sources/src/rln/RLN.sol

    #[sol(rpc, bytecode="")]
    contract RLN {

        error RLN__MemberNotFound();
        error RLN__IdCommitmentAlreadyRegistered();
        error RLN__Unauthorized();
        error RLN__InvalidRevealStartTime();
        error RLN__InvalidCommitment(address expected);
        error RLN__RevealWindowNotStarted();
        error RLN__InvalidSlashRevealWindowTime(uint256 windowTime);

        event MemberRegistered(uint256 identityCommitment, uint256 index);
        event MemberSlashed(uint256 index, address slasher);

        struct User {
            address userAddress;
            uint256 index;
        }

        uint256 public identityCommitmentIndex;

        function register(uint256 identityCommitment, address user) external onlyRole(REGISTER_ROLE);
        // mapping(uint256 commitment => User user) public members;
        function members(uint256 commitment) public view returns (User memory);

        function slashCommit(address account, bytes32 hash) external onlyRole(SLASHER_ROLE);

        // mapping(address account => uint256 lastRevealStartTime) public lastRevealStartTime;
        function lastRevealStartTime(address account) public view returns (uint256);

        // mapping(address account => mapping(bytes32 hash => uint256 revealStartTime)) public slashCommitments;
        function slashCommitments(address account, bytes32 hash) public view returns (uint256);

        function slashReveal(
            address account,
            bytes32 privateKey,
            address rewardRecipient
        ) external onlyRole(SLASHER_ROLE);

        function initialize(
            address _owner,
            address _slasher,
            address _register,
            address _token,
            address _poseidonHasher
        ) public initializer;

        // for bin_tests
        bytes32 public constant SLASHER_ROLE = keccak256("SLASHER_ROLE");
        bytes32 public constant REGISTER_ROLE = keccak256("REGISTER_ROLE");
        function karma() public view return (address);
        function hasRole(bytes32 role, address account) public view returns (bool);
    }
}

#[async_trait]
impl<T: Provider> RLNRegister for RLN::RLNInstance<T> {
    type Error = alloy::contract::Error;

    async fn register_user(
        &self,
        address: &Address,
        identity_commitment: U256,
    ) -> Result<(), Self::Error> {
        self.register(identity_commitment, *address)
            .send()
            .await?
            .watch()
            .await?;
        Ok(())
    }
}

#[cfg(feature = "anvil")]
#[cfg(test)]
mod tests {
    use super::*;
    // third-party
    use crate::KarmaSC;
    use alloy::primitives::address;
    use alloy::providers::ProviderBuilder;
    use alloy::sol_types::SolCall;

    const ADDR_ALICE: Address = address!("0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266");
    const ADDR_BOB: Address = address!("0x70997970C51812dc3A010C7d01b50e0d17dc79C8");
    const ADDR_MICKEY: Address = address!("0x3C44CdDdB6a900fa2b585dd299e03d12FA4293BC");

    sol! {
        // src: status-network-contracts/src/rln/PoseidonHasher.sol
        // Compile bytecode (in status-network-contracts)
        // docker run -v ./:/sources ethereum/solc:0.8.26 --bin --via-ir --optimize --optimize-runs 1 --overwrite  @openzeppelin/contracts=/sources/lib/openzeppelin-contracts/contracts @openzeppelin/contracts-upgradeable=/sources/lib/openzeppelin-contracts-upgradeable/contracts /sources/src/rln/PoseidonHasher.sol

        #[sol(rpc, bytecode="")]
        contract PoseidonHasher is IPoseidonHasher {
            function hash(uint256 input) external pure override returns (uint256 result);
            function identity() external pure override returns (uint256);
        }
    }

    #[tokio::test]
    async fn test_register() {
        let provider = ProviderBuilder::new().connect_anvil_with_wallet();

        // Deploy the KarmaTiers contract.
        let contract_0 = KarmaSC::deploy(&provider).await.unwrap();
        let init_data = KarmaSC::initializeCall { _owner: ADDR_ALICE }.abi_encode();
        let contract_proxy = crate::karma_sc::tests::ERC1967Proxy::deploy(
            &provider,
            *contract_0.address(),
            init_data.into(),
        )
        .await
        .unwrap();
        println!("contract_proxy: {:?}", contract_proxy.address());
        let contract = KarmaSC::new(*contract_proxy.address(), &provider);
        println!("contract KarmaSC: {:?}", contract_proxy.address());

        // Deploy PoseidonHasher contract
        let contract_poseidon_hasher = PoseidonHasher::deploy(&provider).await.unwrap();

        // Deploy RLN SC

        let contract_rln_0 = RLN::deploy(&provider).await.unwrap();
        let init_data_1 = RLN::initializeCall {
            _owner: ADDR_ALICE,
            _slasher: ADDR_ALICE,
            _register: ADDR_ALICE,
            _token: *contract.address(),
            _poseidonHasher: *contract_poseidon_hasher.address(),
        }
        .abi_encode();
        let contract_proxy_rln = crate::karma_sc::tests::ERC1967Proxy::deploy(
            &provider,
            *contract_rln_0.address(),
            init_data_1.into(),
        )
        .await
        .unwrap();
        println!("contract_proxy_rln: {:?}", contract_proxy_rln.address());
        let contract_rln = RLN::new(*contract_proxy_rln.address(), &provider);

        let id_commitment = U256::from(1);
        let call_1 = contract_rln.register(id_commitment, ADDR_BOB);
        let tx_hash_1 = call_1.send().await.unwrap().watch().await.unwrap();
        println!("tx_hash_1: {:?}", tx_hash_1);

        let id_commitment_2 = U256::from(2);
        // let call_2 = contract_rln.register(id_commitment_2, addr_mickey);
        // let tx_hash_2 = call_2.send().await.unwrap().watch().await.unwrap();
        // println!("tx_hash_2: {:?}", tx_hash_2);

        contract_rln
            .register_user(&ADDR_MICKEY, id_commitment_2)
            .await
            .unwrap();

        let result = contract_rln.members(id_commitment).call().await.unwrap();
        assert_eq!(result.userAddress, ADDR_BOB);
        assert_eq!(result.index, U256::from(0));
        let result = contract_rln.members(id_commitment_2).call().await.unwrap();
        assert_eq!(result.userAddress, ADDR_MICKEY);
        assert_eq!(result.index, U256::from(1));
    }
}
